def session_key(session_id: str) -> str:
    return f"session:{session_id}"


def cache_key(prefix: str, *args, **kwargs) -> str:
    payload = {
        "args": args,
        "kwargs": kwargs,
    }
    serialized = json.dumps(payload, sort_keys=True, default=str, separators=(",", ":"))
    return f"cache:{prefix}:{serialized}"


def get_session(session_id: str) -> dict:
    if not session_id:
        return {}
    raw = redis_client.get(session_key(session_id))
    if not raw:
        return {}
    try:
        return json.loads(raw.decode("utf-8"))
    except Exception:
        return {}


def save_session(session_id: str, data: dict, ttl: int = SESSION_TTL_SECONDS) -> None:
    redis_client.set(session_key(session_id), json.dumps(data), ex=ttl)


def delete_session(session_id: str) -> None:
    if session_id:
        redis_client.delete(session_key(session_id))


def cached(ttl: int = CACHE_DEFAULT_TTL_SECONDS, key_prefix: str = None):
    def decorator(func):
        prefix = key_prefix or func.__name__

        @wraps(func)
        def wrapper(*args, **kwargs):
            key = cache_key(prefix, *args, **kwargs)
            cached_value = redis_client.get(key)
            if cached_value is not None:
                return pickle.loads(cached_value)

            result = func(*args, **kwargs)
            redis_client.set(key, pickle.dumps(result), ex=ttl)
            return result

        return wrapper

    return decorator


