@app.before_request
def load_request_session():
    sid = request.cookies.get(SESSION_COOKIE_NAME)
    if not sid:
        sid = str(uuid4())
        g.new_session = True
    else:
        g.new_session = False

    g.session_id = sid
    g.session = get_session(sid)

    if not g.session:
        g.session = {
            "created_at": int(time.time()),
            "visits": 0,
        }


@app.after_request
def persist_request_session(response):
    g.session["visits"] = int(g.session.get("visits", 0)) + 1
    g.session["last_seen"] = int(time.time())
    save_session(g.session_id, g.session, ttl=SESSION_TTL_SECONDS)
    response.set_cookie(
        SESSION_COOKIE_NAME,
        g.session_id,
        max_age=SESSION_TTL_SECONDS,
        httponly=True,
        secure=False,
        samesite="Lax",
    )
    return response


