@app.route("/login", methods=["POST"])
def login():
    payload = request.get_json(silent=True) or {}
    username = payload.get("username", "anonymous")
    g.session["user"] = {"username": username}
    save_session(g.session_id, g.session, ttl=SESSION_TTL_SECONDS)
    return jsonify({"status": "logged_in", "session": g.session})


@app.route("/logout", methods=["POST"])
def logout():
    delete_session(g.session_id)
    response = make_response(jsonify({"status": "logged_out"}))
    response.delete_cookie(SESSION_COOKIE_NAME)
    return response


@app.route("/me")
def me():
    return jsonify(
        {
            "session_id": g.session_id,
            "session": g.session,
            "authenticated": "user" in g.session,
        }
    )


